import{_ as e,o as n,c as a,a4 as l}from"./chunks/framework._in6GHBg.js";const y=JSON.parse('{"title":"高考物理趋势分析与应试策略","description":"","frontmatter":{},"headers":[],"relativePath":"physics/review-guide.md","filePath":"physics/review-guide.md"}'),s={name:"physics/review-guide.md"};function i(d,t,p,r,g,c){return n(),a("div",null,[...t[0]||(t[0]=[l(`<h1 id="高考物理趋势分析与应试策略" tabindex="-1">高考物理趋势分析与应试策略 <a class="header-anchor" href="#高考物理趋势分析与应试策略" aria-label="Permalink to &quot;高考物理趋势分析与应试策略&quot;">​</a></h1><p><strong>方法层 · 趋势分析 · 数据待填充</strong></p><hr><h2 id="使用说明" tabindex="-1">使用说明 <a class="header-anchor" href="#使用说明" aria-label="Permalink to &quot;使用说明&quot;">​</a></h2><p>本文档采用<strong>框架+数据</strong>结构：</p><ul><li><strong>框架</strong>：分析维度、表格结构、方法论（已完整）</li><li><strong>数据</strong>：具体统计数字、真题来源（待后续填充）</li></ul><p><strong>填充方式</strong>：</p><ol><li>近5年真题分类统计 → 填入模块1表格</li><li>当年模拟题风向 → 更新模块3热点预测</li><li>个人错题数据 → 调整模块4个人优先级</li></ol><hr><h2 id="模块1-考点频率统计-数据驱动区" tabindex="-1">模块1：考点频率统计（数据驱动区） <a class="header-anchor" href="#模块1-考点频率统计-数据驱动区" aria-label="Permalink to &quot;模块1：考点频率统计（数据驱动区）&quot;">​</a></h2><h3 id="_1-1-25模型高考出现率统计表" tabindex="-1">1.1 25模型高考出现率统计表 <a class="header-anchor" href="#_1-1-25模型高考出现率统计表" aria-label="Permalink to &quot;1.1 25模型高考出现率统计表&quot;">​</a></h3><p><strong>统计范围</strong>：【待填：全国卷I/II/III 或 新高考XX卷】 <strong>统计年份</strong>：2020-2024年</p><table tabindex="0"><thead><tr><th style="text-align:left;">模型</th><th style="text-align:center;">编号</th><th style="text-align:center;">2024</th><th style="text-align:center;">2023</th><th style="text-align:center;">2022</th><th style="text-align:center;">2021</th><th style="text-align:center;">2020</th><th style="text-align:center;">出现率</th><th style="text-align:center;">趋势</th><th style="text-align:center;">优先级</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>电磁学</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td style="text-align:left;">单杆切割</td><td style="text-align:center;">24</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">__%</td><td style="text-align:center;">↑→↓</td><td style="text-align:center;">P__</td></tr><tr><td style="text-align:left;">双杆切割</td><td style="text-align:center;">25</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">__%</td><td style="text-align:center;">↑→↓</td><td style="text-align:center;">P__</td></tr><tr><td style="text-align:left;">复合场</td><td style="text-align:center;">23</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">__%</td><td style="text-align:center;">↑→↓</td><td style="text-align:center;">P__</td></tr><tr><td style="text-align:left;">磁场粒子</td><td style="text-align:center;">22</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">__%</td><td style="text-align:center;">↑→↓</td><td style="text-align:center;">P__</td></tr><tr><td style="text-align:left;">电场粒子</td><td style="text-align:center;">21</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">__%</td><td style="text-align:center;">↑→↓</td><td style="text-align:center;">P__</td></tr><tr><td style="text-align:left;"><strong>能量动量</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td style="text-align:left;">能量动量综合</td><td style="text-align:center;">20</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">__%</td><td style="text-align:center;">↑→↓</td><td style="text-align:center;">P__</td></tr><tr><td style="text-align:left;">动量守恒</td><td style="text-align:center;">19</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">__%</td><td style="text-align:center;">↑→↓</td><td style="text-align:center;">P__</td></tr><tr><td style="text-align:left;"><strong>力学综合</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td style="text-align:left;">传送带</td><td style="text-align:center;">10</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">__%</td><td style="text-align:center;">↑→↓</td><td style="text-align:center;">P__</td></tr><tr><td style="text-align:left;">板块</td><td style="text-align:center;">11</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">__%</td><td style="text-align:center;">↑→↓</td><td style="text-align:center;">P__</td></tr><tr><td style="text-align:left;">弹簧</td><td style="text-align:center;">12</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">__%</td><td style="text-align:center;">↑→↓</td><td style="text-align:center;">P__</td></tr><tr><td style="text-align:left;">圆周运动</td><td style="text-align:center;">13</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">__%</td><td style="text-align:center;">↑→↓</td><td style="text-align:center;">P__</td></tr><tr><td style="text-align:left;">天体运动</td><td style="text-align:center;">15</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">__%</td><td style="text-align:center;">↑→↓</td><td style="text-align:center;">P__</td></tr><tr><td style="text-align:left;"><strong>基础模型</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td style="text-align:left;">匀变速</td><td style="text-align:center;">01</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">__%</td><td style="text-align:center;">↑→↓</td><td style="text-align:center;">P__</td></tr><tr><td style="text-align:left;">静态平衡</td><td style="text-align:center;">05</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">__%</td><td style="text-align:center;">↑→↓</td><td style="text-align:center;">P__</td></tr><tr><td style="text-align:left;">...</td><td style="text-align:center;">...</td><td style="text-align:center;">...</td><td style="text-align:center;">...</td><td style="text-align:center;">...</td><td style="text-align:center;">...</td><td style="text-align:center;">...</td><td style="text-align:center;">...</td><td style="text-align:center;">...</td><td style="text-align:center;">...</td></tr></tbody></table><p><strong>标记说明</strong>：</p><ul><li>● = 大题（计算题）出现</li><li>○ = 小题（选择/实验）出现</li><li>趋势：↑增加 →稳定 ↓减少</li><li>优先级：P0必掌握 P1重点 P2掌握 P3了解</li></ul><p><strong>联动工具层</strong>：</p><ul><li>P0模型 → TS-000速查卡高亮/置顶</li><li>P1模型 → TS详解优先创建</li><li>P2/P3模型 → 按需创建</li></ul><hr><h3 id="_1-2-题型分布分析框架" tabindex="-1">1.2 题型分布分析框架 <a class="header-anchor" href="#_1-2-题型分布分析框架" aria-label="Permalink to &quot;1.2 题型分布分析框架&quot;">​</a></h3><h4 id="选择题-8题-48分" tabindex="-1">选择题（8题，48分） <a class="header-anchor" href="#选择题-8题-48分" aria-label="Permalink to &quot;选择题（8题，48分）&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">常见模型</th><th style="text-align:left;">考查形式</th><th style="text-align:center;">难度</th><th style="text-align:left;">应对策略</th></tr></thead><tbody><tr><td style="text-align:left;">【待填：如天体运动】</td><td style="text-align:left;">【待填：概念辨析】</td><td style="text-align:center;">⭐⭐⭐</td><td style="text-align:left;">【待填：记住关键公式】</td></tr><tr><td style="text-align:left;">【待填：如电磁感应】</td><td style="text-align:left;">【待填：图像分析】</td><td style="text-align:center;">⭐⭐⭐⭐</td><td style="text-align:left;">【待填：看斜率/面积】</td></tr></tbody></table><h4 id="实验题-2题-15分" tabindex="-1">实验题（2题，15分） <a class="header-anchor" href="#实验题-2题-15分" aria-label="Permalink to &quot;实验题（2题，15分）&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">实验类型</th><th style="text-align:left;">原型模型</th><th style="text-align:left;">创新方向</th><th style="text-align:left;">准备策略</th></tr></thead><tbody><tr><td style="text-align:left;">【待填：力学实验】</td><td style="text-align:left;">【待填：如匀变速】</td><td style="text-align:left;">【待填：传感器应用】</td><td style="text-align:left;">掌握纸带分析、图像处理</td></tr><tr><td style="text-align:left;">【待填：电学实验】</td><td style="text-align:left;">【待填：如单杆】</td><td style="text-align:left;">【待填：创新电路】</td><td style="text-align:left;">掌握电路设计、误差分析</td></tr></tbody></table><h4 id="计算题-3题-32分" tabindex="-1">计算题（3题，32分） <a class="header-anchor" href="#计算题-3题-32分" aria-label="Permalink to &quot;计算题（3题，32分）&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:center;">题位</th><th style="text-align:left;">典型模型</th><th style="text-align:center;">难度</th><th style="text-align:left;">目标策略</th></tr></thead><tbody><tr><td style="text-align:center;">第1题（8分）</td><td style="text-align:left;">【待填：力学综合】</td><td style="text-align:center;">⭐⭐⭐</td><td style="text-align:left;">必拿满分</td></tr><tr><td style="text-align:center;">第2题（12分）</td><td style="text-align:left;">【待填：电磁感应】</td><td style="text-align:center;">⭐⭐⭐⭐</td><td style="text-align:left;">第一问必拿，第二问抢分</td></tr><tr><td style="text-align:center;">第3题（12分）</td><td style="text-align:left;">【待填：复合场/创新】</td><td style="text-align:center;">⭐⭐⭐⭐⭐</td><td style="text-align:left;">第一问必拿，后面看时间</td></tr></tbody></table><hr><h3 id="_1-3-分值权重估算方法" tabindex="-1">1.3 分值权重估算方法 <a class="header-anchor" href="#_1-3-分值权重估算方法" aria-label="Permalink to &quot;1.3 分值权重估算方法&quot;">​</a></h3><p><strong>计算方式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>某模型5年总分 = Σ（每年出现的分值）</span></span>
<span class="line"><span>某模型年均分 = 5年总分 / 5</span></span>
<span class="line"><span>权重占比 = 该模型年均分 / 110分（满分）</span></span></code></pre></div><p><strong>示例</strong>（虚拟数据）：</p><table tabindex="0"><thead><tr><th style="text-align:left;">模型</th><th style="text-align:center;">5年总分</th><th style="text-align:center;">年均分</th><th style="text-align:center;">权重占比</th></tr></thead><tbody><tr><td style="text-align:left;">单杆切割</td><td style="text-align:center;">55分</td><td style="text-align:center;">11分</td><td style="text-align:center;">10%</td></tr><tr><td style="text-align:left;">复合场</td><td style="text-align:center;">48分</td><td style="text-align:center;">9.6分</td><td style="text-align:center;">8.7%</td></tr><tr><td style="text-align:left;">传送带</td><td style="text-align:center;">20分</td><td style="text-align:center;">4分</td><td style="text-align:center;">3.6%</td></tr></tbody></table><p><strong>【待填】实际数据区</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">模型</th><th style="text-align:center;">5年总分</th><th style="text-align:center;">年均分</th><th style="text-align:center;">权重占比</th></tr></thead><tbody><tr><td style="text-align:left;">【模型名称】</td><td style="text-align:center;">【待统计】</td><td style="text-align:center;">【待计算】</td><td style="text-align:center;">【待计算】</td></tr></tbody></table><hr><h2 id="模块2-难度演进路径-方法论区" tabindex="-1">模块2：难度演进路径（方法论区） <a class="header-anchor" href="#模块2-难度演进路径-方法论区" aria-label="Permalink to &quot;模块2：难度演进路径（方法论区）&quot;">​</a></h2><h3 id="_2-1-难度提升5条路径详解" tabindex="-1">2.1 难度提升5条路径详解 <a class="header-anchor" href="#_2-1-难度提升5条路径详解" aria-label="Permalink to &quot;2.1 难度提升5条路径详解&quot;">​</a></h3><h4 id="路径1-模型叠加-从单一到复合" tabindex="-1">路径1：模型叠加（从单一到复合） <a class="header-anchor" href="#路径1-模型叠加-从单一到复合" aria-label="Permalink to &quot;路径1：模型叠加（从单一到复合）&quot;">​</a></h4><p><strong>层级演进</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Level 1（基础）：单一模型</span></span>
<span class="line"><span>    例：纯单杆切割，水平导轨，无外力</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>Level 2（中档）：双模型叠加</span></span>
<span class="line"><span>    例：单杆+电容（电磁感应+电路）</span></span>
<span class="line"><span>    例：传送带+斜面（摩擦力+重力分量）</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>Level 3（较难）：三模型叠加</span></span>
<span class="line"><span>    例：单杆+弹簧+斜面（电磁+力学+能量）</span></span>
<span class="line"><span>    例：板块+碰撞（多物体+动量）</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>Level 4（压轴）：多模型+新情境包装</span></span>
<span class="line"><span>    例：电磁弹射背景 = 单杆+能量+设计性</span></span>
<span class="line"><span>    例：磁悬浮背景 = 磁场+电磁感应+多阶段</span></span></code></pre></div><p><strong>识别标志</strong>：</p><ul><li>看有几个物理过程</li><li>看涉及几个知识板块（力/电/磁/能量）</li><li>看是否需要多次切换分析方法</li></ul><p><strong>应对策略</strong>：</p><ul><li>拆解：把复合问题拆成单模型序列</li><li>衔接：找相邻模型的联系点（速度/能量/位置）</li><li>工具：TS-000速查卡组合使用</li></ul><hr><h4 id="路径2-过程复杂化-从单段到多段" tabindex="-1">路径2：过程复杂化（从单段到多段） <a class="header-anchor" href="#路径2-过程复杂化-从单段到多段" aria-label="Permalink to &quot;路径2：过程复杂化（从单段到多段）&quot;">​</a></h4><p><strong>层级演进</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Level 1（基础）：单一过程</span></span>
<span class="line"><span>    例：一直匀加速</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>Level 2（中档）：两段过程+临界点</span></span>
<span class="line"><span>    例：先加速后匀速（找共速点）</span></span>
<span class="line"><span>    例：先平抛后圆周（找衔接速度）</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>Level 3（较难）：多段过程+转折点</span></span>
<span class="line"><span>    例：加速→匀速→减速→反向（3个转折点）</span></span>
<span class="line"><span>    例：多次碰撞（每次碰撞后状态变化）</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>Level 4（压轴）：周期性/循环过程</span></span>
<span class="line"><span>    例：往复运动（每次能量损失）</span></span>
<span class="line"><span>    例：多体碰撞后求通项（数列递推）</span></span></code></pre></div><p><strong>识别标志</strong>：</p><ul><li>看v-t图像的段数</li><li>看题目中的&quot;然后&quot;&quot;接着&quot;&quot;最终&quot;等转折词</li><li>看是否有&quot;多次&quot;&quot;反复&quot;等关键词</li></ul><p><strong>应对策略</strong>：</p><ul><li>画v-t图：直观展示过程转折</li><li>分段列表：每段的初速度、加速度、位移</li><li>找不变量：哪些量在转折点守恒（速度？能量？）</li></ul><hr><h4 id="路径3-条件隐蔽化-从显给到隐含" tabindex="-1">路径3：条件隐蔽化（从显给到隐含） <a class="header-anchor" href="#路径3-条件隐蔽化-从显给到隐含" aria-label="Permalink to &quot;路径3：条件隐蔽化（从显给到隐含）&quot;">​</a></h4><p><strong>层级演进</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Level 1（基础）：条件直接给出</span></span>
<span class="line"><span>    例：已知μ=0.2，m=2kg，求...</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>Level 2（中档）：条件半隐含</span></span>
<span class="line"><span>    例：&quot;刚好不掉下去&quot;→隐含v=0在边缘</span></span>
<span class="line"><span>    例：&quot;恰好不飞出&quot;→隐含临界轨迹与边界相切</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>Level 3（较难）：条件完全隐含在图像中</span></span>
<span class="line"><span>    例：v-t图像斜率=加速度</span></span>
<span class="line"><span>    例：F-x图像面积=功</span></span>
<span class="line"><span>    例：E-x图像分析电势变化</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>Level 4（压轴）：条件隐含在实际背景中</span></span>
<span class="line"><span>    例：&quot;电磁弹射起飞&quot;→隐含加速距离有限</span></span>
<span class="line"><span>    例：&quot;磁悬浮稳定悬浮&quot;→隐含平衡条件</span></span></code></pre></div><p><strong>识别标志</strong>：</p><ul><li>是否有&quot;恰好&quot;&quot;刚好&quot;&quot;恰能&quot;等关键词</li><li>是否给图像而非直接数据</li><li>是否有大量背景描述（需要剥离）</li></ul><p><strong>应对策略</strong>：</p><ul><li>关键词翻译：把&quot;刚好不掉&quot;翻译成v=0, x=L</li><li>图像读数：先看轴标签，再看斜率/截距/面积</li><li>去情境化：剥掉背景，找核心物理过程</li></ul><hr><h4 id="路径4-数学工具升级" tabindex="-1">路径4：数学工具升级 <a class="header-anchor" href="#路径4-数学工具升级" aria-label="Permalink to &quot;路径4：数学工具升级&quot;">​</a></h4><p><strong>层级演进</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Level 1（基础）：代数运算</span></span>
<span class="line"><span>    一元一次/二次方程求解</span></span>
<span class="line"><span>    例：F=ma，已知F和m求a</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>Level 2（中档）：函数分析</span></span>
<span class="line"><span>    求极值、单调性、范围</span></span>
<span class="line"><span>    例：最大功率、最远距离、时间范围</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>Level 3（较难）：几何分析</span></span>
<span class="line"><span>    圆的几何关系、三角函数</span></span>
<span class="line"><span>    例：磁场中粒子轨迹的圆心角、弦长</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>Level 4（压轴）：数列递推</span></span>
<span class="line"><span>    多次碰撞后的通项公式</span></span>
<span class="line"><span>    例：n次碰撞后的速度、总路程</span></span></code></pre></div><p><strong>识别标志</strong>：</p><ul><li>看问题是否求&quot;最大/最小&quot;</li><li>看是否涉及圆/三角形几何</li><li>看是否有&quot;多次&quot;&quot;第n次&quot;</li></ul><p><strong>应对策略</strong>：</p><ul><li>极值：函数求导或配方法</li><li>几何：画标准图，标圆心、半径、角度</li><li>数列：求前几项找规律，数学归纳法证明</li></ul><hr><h4 id="路径5-思维方向反转" tabindex="-1">路径5：思维方向反转 <a class="header-anchor" href="#路径5-思维方向反转" aria-label="Permalink to &quot;路径5：思维方向反转&quot;">​</a></h4><p><strong>层级演进</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Level 1（基础）：正向思维</span></span>
<span class="line"><span>    已知条件→求结果</span></span>
<span class="line"><span>    例：已知F、m、t，求v</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>Level 2（中档）：逆向思维</span></span>
<span class="line"><span>    已知结果→反推条件</span></span>
<span class="line"><span>    例：已知末速度v，求初速度或受力</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>Level 3（较难）：范围讨论</span></span>
<span class="line"><span>    求使结果成立的参数范围</span></span>
<span class="line"><span>    例：求使物块不掉下去的μ的范围</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>Level 4（压轴）：设计性思维</span></span>
<span class="line"><span>    设计方案使结果满足条件</span></span>
<span class="line"><span>    例：设计磁场区域使粒子偏转特定角度</span></span></code></pre></div><p><strong>识别标志</strong>：</p><ul><li>问题以&quot;求...的范围&quot;出现</li><li>问题以&quot;设计/计算...使...&quot;出现</li><li>需要多解性分析</li></ul><p><strong>应对策略</strong>：</p><ul><li>逆向：从结果倒推，列方程反解</li><li>范围：找临界条件（等号成立时），确定边界</li><li>设计：逆向+范围结合，先定目标再调参数</li></ul><hr><h3 id="_2-2-各模型难度天花板对照表" tabindex="-1">2.2 各模型难度天花板对照表 <a class="header-anchor" href="#_2-2-各模型难度天花板对照表" aria-label="Permalink to &quot;2.2 各模型难度天花板对照表&quot;">​</a></h3><p><strong>说明</strong>：每个模型按5条路径提升到最高难度的示例</p><table tabindex="0"><thead><tr><th style="text-align:left;">模型</th><th style="text-align:left;">Level1基础</th><th style="text-align:left;">Level2中档</th><th style="text-align:left;">Level3较难</th><th style="text-align:left;">Level4压轴</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>单杆切割</strong></td><td style="text-align:left;">水平导轨，无外力，求v</td><td style="text-align:left;">倾斜导轨+外力，求最大速度</td><td style="text-align:left;">单杆+电容，求电量</td><td style="text-align:left;">双杆+弹簧，求最终状态</td></tr><tr><td style="text-align:left;"><strong>传送带</strong></td><td style="text-align:left;">水平传送带，求时间</td><td style="text-align:left;">倾斜传送带，判断能否共速</td><td style="text-align:left;">多次往返，求总热量</td><td style="text-align:left;">与碰撞结合，求最终位置</td></tr><tr><td style="text-align:left;"><strong>复合场</strong></td><td style="text-align:left;">先电后磁，求半径</td><td style="text-align:left;">E+B同区域，判断运动</td><td style="text-align:left;">配速法，分解运动</td><td style="text-align:left;">设计场区，实现特定轨迹</td></tr><tr><td style="text-align:left;"><strong>【待补充】</strong></td><td style="text-align:left;">【待填】</td><td style="text-align:left;">【待填】</td><td style="text-align:left;">【待填】</td><td style="text-align:left;">【待填】</td></tr></tbody></table><p><strong>联动工具层</strong>：</p><ul><li>Level1-2 → TS-000速查卡</li><li>Level3 → TS-XXX详解【基础/中档版】</li><li>Level4 → TS-XXX详解【压轴版】+ 套路模板</li></ul><hr><h2 id="模块3-新情境归位-实战关键区" tabindex="-1">模块3：新情境归位（实战关键区） <a class="header-anchor" href="#模块3-新情境归位-实战关键区" aria-label="Permalink to &quot;模块3：新情境归位（实战关键区）&quot;">​</a></h2><h3 id="_3-1-科技热点映射表-可扩展" tabindex="-1">3.1 科技热点映射表（可扩展） <a class="header-anchor" href="#_3-1-科技热点映射表-可扩展" aria-label="Permalink to &quot;3.1 科技热点映射表（可扩展）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">热点背景</th><th style="text-align:left;">物理本质</th><th style="text-align:center;">对应模型</th><th style="text-align:left;">工具层资源</th><th style="text-align:center;">难度</th></tr></thead><tbody><tr><td style="text-align:left;">电磁弹射</td><td style="text-align:left;">单杆切割+能量转化+设计</td><td style="text-align:center;">24</td><td style="text-align:left;">TS-024详解、单杆套路</td><td style="text-align:center;">⭐⭐⭐⭐</td></tr><tr><td style="text-align:left;">磁悬浮列车</td><td style="text-align:left;">磁场+电磁感应+多阶段</td><td style="text-align:center;">22+24</td><td style="text-align:left;">复合场套路</td><td style="text-align:center;">⭐⭐⭐⭐⭐</td></tr><tr><td style="text-align:left;">霍尔推进器</td><td style="text-align:left;">电场+磁场复合</td><td style="text-align:center;">23</td><td style="text-align:left;">TS-023详解、复合场套路</td><td style="text-align:center;">⭐⭐⭐⭐</td></tr><tr><td style="text-align:left;">无线充电</td><td style="text-align:left;">互感/变压器原理</td><td style="text-align:center;">—</td><td style="text-align:left;">【待创建】</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td style="text-align:left;">粒子加速器</td><td style="text-align:left;">复合场+多次加速</td><td style="text-align:center;">21+22+23</td><td style="text-align:left;">TS-021/022/023详解</td><td style="text-align:center;">⭐⭐⭐⭐⭐</td></tr><tr><td style="text-align:left;">电磁阻尼制动</td><td style="text-align:left;">单杆切割+安培力</td><td style="text-align:center;">24</td><td style="text-align:left;">TS-024详解</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td style="text-align:left;">电磁流量计</td><td style="text-align:left;">霍尔效应+电势差</td><td style="text-align:center;">22</td><td style="text-align:left;">TS-022详解</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td style="text-align:left;">【待补充】</td><td style="text-align:left;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:left;">【待填】</td><td style="text-align:center;">【待填】</td></tr></tbody></table><p><strong>填充方式</strong>：</p><ol><li>关注当年科技新闻（如航天发射、新基建）</li><li>收集名校模拟题中的新情境</li><li>归类到已有模型或创建新模型</li></ol><hr><h3 id="_3-2-去情境化方法-通用方法论" tabindex="-1">3.2 去情境化方法（通用方法论） <a class="header-anchor" href="#_3-2-去情境化方法-通用方法论" aria-label="Permalink to &quot;3.2 去情境化方法（通用方法论）&quot;">​</a></h3><p><strong>核心思想</strong>：新情境 = 经典模型 + 背景包装</p><p><strong>四步法</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>【Step1】读题抓过程</span></span>
<span class="line"><span>    划出：物体、运动过程、能量转化</span></span>
<span class="line"><span>    忽略：背景描述、专业术语、装置细节</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【Step2】画草图抽象</span></span>
<span class="line"><span>    画出：初态、末态、关键位置</span></span>
<span class="line"><span>    标注：已知量、未知量、约束条件</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【Step3】定位经典模型</span></span>
<span class="line"><span>    对比：25个模型特征</span></span>
<span class="line"><span>    判断：是哪个或哪几个模型的组合</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【Step4】调用工具层</span></span>
<span class="line"><span>    速查：TS-000查公式</span></span>
<span class="line"><span>    详解：TS-XXX看推导</span></span>
<span class="line"><span>    套路：模板看步骤</span></span></code></pre></div><p><strong>示例演示</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>【原题】电磁弹射起飞装置...</span></span>
<span class="line"><span>（大量背景描述，装置示意图）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【Step1抓过程】</span></span>
<span class="line"><span>导体棒在磁场中加速运动，从静止到v，位移L</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【Step2画草图】</span></span>
<span class="line"><span>初态：v₀=0</span></span>
<span class="line"><span>末态：v=vₘ，x=L</span></span>
<span class="line"><span>过程：匀加速（或变加速）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【Step3定位模型】</span></span>
<span class="line"><span>→ 单杆切割模型（24）</span></span>
<span class="line"><span>  电磁弹射 = 单杆 + 大电流 + 设计性</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【Step4调用资源】</span></span>
<span class="line"><span>→ TS-000查公式：ε=BLv, F安=BIL</span></span>
<span class="line"><span>→ 单杆套路：分恒流/恒压两种情况</span></span>
<span class="line"><span>→ 注意：弹射需要设计电流随时间变化</span></span></code></pre></div><hr><h3 id="_3-3-202x年热点预测-动态更新区" tabindex="-1">3.3 202X年热点预测（动态更新区） <a class="header-anchor" href="#_3-3-202x年热点预测-动态更新区" aria-label="Permalink to &quot;3.3 202X年热点预测（动态更新区）&quot;">​</a></h3><p><strong>预测方法</strong>：</p><ol><li>当年重大科技事件（航天、新能源、半导体）</li><li>教材修订新增内容</li><li>上一年真题风向</li><li>名校模拟题集中出现的新情境</li></ol><p><strong>【202X年待更新】</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">预测热点</th><th style="text-align:left;">理由</th><th style="text-align:center;">可能关联模型</th><th style="text-align:center;">准备程度</th></tr></thead><tbody><tr><td style="text-align:left;">【待填】</td><td style="text-align:left;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">□已准备 □待复习</td></tr><tr><td style="text-align:left;">【待填】</td><td style="text-align:left;">【待填】</td><td style="text-align:center;">【待填】</td><td style="text-align:center;">□已准备 □待复习</td></tr></tbody></table><p><strong>更新频率</strong>：建议每月回顾一次，考前1周最终确认</p><hr><h2 id="模块4-应试策略-决策指南区" tabindex="-1">模块4：应试策略（决策指南区） <a class="header-anchor" href="#模块4-应试策略-决策指南区" aria-label="Permalink to &quot;模块4：应试策略（决策指南区）&quot;">​</a></h2><h3 id="_4-1-时间分配策略" tabindex="-1">4.1 时间分配策略 <a class="header-anchor" href="#_4-1-时间分配策略" aria-label="Permalink to &quot;4.1 时间分配策略&quot;">​</a></h3><p><strong>标准卷结构（110分，75分钟）</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">题型</th><th style="text-align:center;">题号</th><th style="text-align:center;">分值</th><th style="text-align:center;">建议用时</th><th style="text-align:center;">得分目标</th><th style="text-align:left;">取舍原则</th></tr></thead><tbody><tr><td style="text-align:left;">单选题</td><td style="text-align:center;">1-7</td><td style="text-align:center;">28分</td><td style="text-align:center;">15分钟</td><td style="text-align:center;">28分</td><td style="text-align:left;">快做，不纠结</td></tr><tr><td style="text-align:left;">多选题</td><td style="text-align:center;">8-10</td><td style="text-align:center;">18分</td><td style="text-align:center;">10分钟</td><td style="text-align:center;">12-18分</td><td style="text-align:left;">拿不准选少不选多</td></tr><tr><td style="text-align:left;">实验题</td><td style="text-align:center;">11-12</td><td style="text-align:center;">15分</td><td style="text-align:center;">15分钟</td><td style="text-align:center;">12分</td><td style="text-align:left;">力学必拿，电学抢分</td></tr><tr><td style="text-align:left;">计算题第1题</td><td style="text-align:center;">13</td><td style="text-align:center;">8分</td><td style="text-align:center;">10分钟</td><td style="text-align:center;">8分</td><td style="text-align:left;"><strong>必拿满分</strong></td></tr><tr><td style="text-align:left;">计算题第2题</td><td style="text-align:center;">14</td><td style="text-align:center;">12分</td><td style="text-align:center;">15分钟</td><td style="text-align:center;">8-10分</td><td style="text-align:left;">第一问必拿，第二问列式</td></tr><tr><td style="text-align:left;">计算题第3题</td><td style="text-align:center;">15</td><td style="text-align:center;">12分</td><td style="text-align:center;">15分钟</td><td style="text-align:center;">4-8分</td><td style="text-align:left;">第一问必拿，后面看时间</td></tr><tr><td style="text-align:left;">检查/机动</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">5分钟</td><td style="text-align:center;">—</td><td style="text-align:left;">—</td></tr></tbody></table><p><strong>【个性化调整区】</strong>： 根据模考数据调整：</p><ul><li>我实验题平均用时：__分钟（建议15分钟）</li><li>我压轴题平均得分：__分（建议保4分争8分）</li><li>我选择题易错类型：________（针对性提速）</li></ul><hr><h3 id="_4-2-模型优先级-基于模块1数据" tabindex="-1">4.2 模型优先级（基于模块1数据） <a class="header-anchor" href="#_4-2-模型优先级-基于模块1数据" aria-label="Permalink to &quot;4.2 模型优先级（基于模块1数据）&quot;">​</a></h3><p><strong>P0：必掌握（出现率≥80%或年均分≥10分）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>【待填，示例】</span></span>
<span class="line"><span>- 单杆切割（24）：电磁感应核心，压轴题常客</span></span>
<span class="line"><span>- 复合场（23）：区分度最高，能力综合考查</span></span>
<span class="line"><span>- 能量动量综合（20）：力学压轴，多过程综合</span></span></code></pre></div><p><strong>策略</strong>：必须熟练掌握，看到就能动笔</p><p><strong>P1：重点掌握（出现率50-80%或年均分5-10分）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>【待填，示例】</span></span>
<span class="line"><span>- 双杆切割（25）</span></span>
<span class="line"><span>- 板块模型（11）</span></span>
<span class="line"><span>- 传送带模型（10）</span></span></code></pre></div><p><strong>策略</strong>：常规题必拿，变式题能抢分</p><p><strong>P2：掌握（出现率30-50%）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>【待填】</span></span></code></pre></div><p><strong>策略</strong>：基础题不丢分，难题能拿步骤分</p><p><strong>P3：了解（出现率&lt;30%）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>【待填】</span></span></code></pre></div><p><strong>策略</strong>：时间不够时可策略性放弃压轴问</p><p><strong>联动工具层</strong>：</p><ul><li>P0 → TS-000高亮 + TS详解完整版 + 套路模板</li><li>P1 → TS-000标准 + TS详解中档版 + 套路模板</li><li>P2/P3 → TS-000基础 + 详解按需</li></ul><hr><h3 id="_4-3-考场应急策略" tabindex="-1">4.3 考场应急策略 <a class="header-anchor" href="#_4-3-考场应急策略" aria-label="Permalink to &quot;4.3 考场应急策略&quot;">​</a></h3><h4 id="场景1-3分钟没思路" tabindex="-1">场景1：3分钟没思路 <a class="header-anchor" href="#场景1-3分钟没思路" aria-label="Permalink to &quot;场景1：3分钟没思路&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>决策：跳过，做下一题</span></span>
<span class="line"><span>标记：在题号旁画△，做完再回</span></span>
<span class="line"><span>心理：不是放弃，是战略转移</span></span></code></pre></div><h4 id="场景2-做到一半卡壳" tabindex="-1">场景2：做到一半卡壳 <a class="header-anchor" href="#场景2-做到一半卡壳" aria-label="Permalink to &quot;场景2：做到一半卡壳&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>决策：看是否已拿部分分</span></span>
<span class="line"><span>- 已列原始公式：有过程分，可以继续试</span></span>
<span class="line"><span>- 完全没思路：标记跳过，不留恋</span></span></code></pre></div><h4 id="场景3-时间不够-剩15分钟还有2道大题" tabindex="-1">场景3：时间不够（剩15分钟还有2道大题） <a class="header-anchor" href="#场景3-时间不够-剩15分钟还有2道大题" aria-label="Permalink to &quot;场景3：时间不够（剩15分钟还有2道大题）&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>优先级：</span></span>
<span class="line"><span>1. 计算题第1题（简单，必拿）</span></span>
<span class="line"><span>2. 计算题第2题第一问（基础，必拿）</span></span>
<span class="line"><span>3. 计算题第3题第一问（4分，争取）</span></span>
<span class="line"><span>4. 其余：列原始公式抢过程分</span></span>
<span class="line"><span></span></span>
<span class="line"><span>策略：不求做完，只求把会的分拿到</span></span></code></pre></div><h4 id="场景4-遇到新情境题" tabindex="-1">场景4：遇到新情境题 <a class="header-anchor" href="#场景4-遇到新情境题" aria-label="Permalink to &quot;场景4：遇到新情境题&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>应对：</span></span>
<span class="line"><span>1. 深呼吸（新情境≠超纲）</span></span>
<span class="line"><span>2. 用3.2去情境化四步法</span></span>
<span class="line"><span>3. 定位到P0/P1模型，调用熟悉资源</span></span>
<span class="line"><span>4. 即使不能完全做对，也要列相关公式抢分</span></span></code></pre></div><hr><h2 id="模块5-与工具层联动索引" tabindex="-1">模块5：与工具层联动索引 <a class="header-anchor" href="#模块5-与工具层联动索引" aria-label="Permalink to &quot;模块5：与工具层联动索引&quot;">​</a></h2><h3 id="_5-1-速查卡联动" tabindex="-1">5.1 速查卡联动 <a class="header-anchor" href="#_5-1-速查卡联动" aria-label="Permalink to &quot;5.1 速查卡联动&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">本文档提及</th><th style="text-align:left;">TS-000对应</th><th style="text-align:left;">联动方式</th></tr></thead><tbody><tr><td style="text-align:left;">P0优先级模型</td><td style="text-align:left;">高亮/置顶显示</td><td style="text-align:left;">视觉优先</td></tr><tr><td style="text-align:left;">易错点提醒</td><td style="text-align:left;">速查表&quot;易错点&quot;列</td><td style="text-align:left;">对应填充</td></tr><tr><td style="text-align:left;">新情境映射</td><td style="text-align:left;">模型编号旁标注★</td><td style="text-align:left;">热点提示</td></tr></tbody></table><h3 id="_5-2-详解文档联动" tabindex="-1">5.2 详解文档联动 <a class="header-anchor" href="#_5-2-详解文档联动" aria-label="Permalink to &quot;5.2 详解文档联动&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">本文档难度层级</th><th style="text-align:left;">TS详解分层</th><th style="text-align:left;">联动方式</th></tr></thead><tbody><tr><td style="text-align:left;">Level1-2基础</td><td style="text-align:left;">【基础版】章节</td><td style="text-align:left;">必须掌握</td></tr><tr><td style="text-align:left;">Level3中档</td><td style="text-align:left;">【中档版】章节</td><td style="text-align:left;">重点掌握</td></tr><tr><td style="text-align:left;">Level4压轴</td><td style="text-align:left;">【压轴版】章节</td><td style="text-align:left;">冲刺高分</td></tr></tbody></table><h3 id="_5-3-套路模板联动" tabindex="-1">5.3 套路模板联动 <a class="header-anchor" href="#_5-3-套路模板联动" aria-label="Permalink to &quot;5.3 套路模板联动&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">本文档高频模型</th><th style="text-align:left;">模板对应</th><th style="text-align:left;">联动方式</th></tr></thead><tbody><tr><td style="text-align:left;">模块2难度分析</td><td style="text-align:left;">套路模板【难度适配】小节</td><td style="text-align:left;">填充案例</td></tr><tr><td style="text-align:left;">模块3新情境</td><td style="text-align:left;">套路模板【新情境适配】小节</td><td style="text-align:left;">扩展应用</td></tr><tr><td style="text-align:left;">模块4应试策略</td><td style="text-align:left;">套路模板【应试策略】小节</td><td style="text-align:left;">题位/用时/取舍</td></tr></tbody></table><h3 id="_5-4-使用流程图" tabindex="-1">5.4 使用流程图 <a class="header-anchor" href="#_5-4-使用流程图" aria-label="Permalink to &quot;5.4 使用流程图&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>备考阶段：</span></span>
<span class="line"><span>    读MG-PHYS-002模块1 → 确定P0/P1/P2模型优先级</span></span>
<span class="line"><span>    读模块2难度路径 → 明确能力提升方向</span></span>
<span class="line"><span>    读模块3新情境 → 建立热点敏感度</span></span>
<span class="line"><span>    读模块4策略 → 制定个人时间分配</span></span>
<span class="line"><span></span></span>
<span class="line"><span>做题卡壳：</span></span>
<span class="line"><span>    查TS-000速查卡 → 找公式</span></span>
<span class="line"><span>    判断难度层级 → 查TS详解对应分层</span></span>
<span class="line"><span>    新情境 → 用3.2去情境化方法 → 定位模型</span></span>
<span class="line"><span>    套路不熟 → 查模板步骤</span></span>
<span class="line"><span></span></span>
<span class="line"><span>考前复习：</span></span>
<span class="line"><span>    过TS-000高亮模型（P0优先）</span></span>
<span class="line"><span>    回顾模块3当年热点预测</span></span>
<span class="line"><span>    确认模块4个人时间分配</span></span></code></pre></div><hr><h2 id="文档控制信息" tabindex="-1">文档控制信息 <a class="header-anchor" href="#文档控制信息" aria-label="Permalink to &quot;文档控制信息&quot;">​</a></h2><p><strong>文档编号</strong>: MG-PHYS-002<br><strong>版本</strong>: V1.0-框架版<br><strong>类别</strong>: 方法层 (MG - Method Guide) - 趋势分析<br><strong>编制日期</strong>: 2026-04-05<br><strong>编制人</strong>: [家长/Kimi Claw]<br><strong>适用对象</strong>: 高三学生（二轮复习后）<br><strong>数据状态</strong>: 框架完整，数据待填充</p><h2 id="变更日志" tabindex="-1">变更日志 <a class="header-anchor" href="#变更日志" aria-label="Permalink to &quot;变更日志&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">版本</th><th style="text-align:center;">日期</th><th style="text-align:left;">变更内容</th><th style="text-align:center;">变更人</th><th style="text-align:left;">备注</th></tr></thead><tbody><tr><td style="text-align:center;">V1.0-框架</td><td style="text-align:center;">2026-04-05</td><td style="text-align:left;">建立四大模块框架、难度路径、联动设计</td><td style="text-align:center;">[家长]</td><td style="text-align:left;">数据区待填充</td></tr></tbody></table><h2 id="待填充清单" tabindex="-1">待填充清单 <a class="header-anchor" href="#待填充清单" aria-label="Permalink to &quot;待填充清单&quot;">​</a></h2><ul><li>[ ] 模块1.1：25模型5年真题统计表</li><li>[ ] 模块1.2：本省题型分布分析</li><li>[ ] 模块1.3：分值权重实际数据</li><li>[ ] 模块2.2：各模型难度天花板示例</li><li>[ ] 模块3.1：科技热点映射表扩展</li><li>[ ] 模块3.3：当年热点预测</li><li>[ ] 模块4.2：基于个人数据的优先级调整</li></ul>`,151)])])}const o=e(s,[["render",i]]);export{y as __pageData,o as default};
